const chunks = $input.all().map(item => item.json);
const lead = $('Get Lead').first().json;

// n8n 2.22.4: pgvector load returns {document: {pageContent, metadata}, score}
const retrievedContext = chunks.map((c, i) => {
  const doc = c.document || c;
  const title = (doc.metadata && doc.metadata.title) ? doc.metadata.title : 'Document';
  const content = doc.pageContent || doc.text || '';
  return '[Source ' + (i + 1) + ': ' + title + ']\n' + content;
}).join('\n\n---\n\n');

const sourcesUsed = JSON.stringify(
  chunks.map(c => {
    const doc = c.document || c;
    return (doc.metadata && doc.metadata.document_id) ? doc.metadata.document_id : 'unknown';
  })
);

return [{
  json: {
    lead_id: lead.id || '',
    lead_name: lead.name || '',
    desired_course: lead.desired_course || 'unknown',
    programme_level: lead.programme_level || 'unknown',
    preferred_countries: lead.preferred_countries || [],
    qualification: lead.qualification || 'unknown',
    english_test_status: lead.english_test_status || 'unknown',
    budget_range: lead.budget_range || 'unknown',
    sponsor_status: lead.sponsor_status || 'unknown',
    missing_fields_str: (lead.missing_fields || []).join(', '),
    sources_used: sourcesUsed,
    retrieved_context: retrievedContext
  }
}];

